import logging
import os
import sys
from logging.handlers import RotatingFileHandler
from pathlib import Path
import stat

def setup_secure_logging(log_file_path, max_bytes=10485760, backup_count=5):
    """Setup secure logging with rotation and proper permissions"""
    
    # Create log directory with secure permissions
    log_dir = Path(log_file_path).parent
    log_dir.mkdir(parents=True, exist_ok=True)
    
    # Set secure permissions on log directory (700)
    log_dir.chmod(stat.S_IRWXU)
    
    # Configure logging
    logger = logging.getLogger('secure_app')
    logger.setLevel(logging.DEBUG)
    
    # Create rotating file handler
    handler = RotatingFileHandler(
        log_file_path,
        maxBytes=max_bytes,
        backupCount=backup_count
    )
    
    # Set secure permissions on log file
    try:
        os.chmod(log_file_path, stat.S_IRUSR | stat.S_IWUSR)
    except OSError:
        pass  # Continue even if chmod fails
    
    # Create formatter
    formatter = logging.Formatter(
        '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
    )
    handler.setFormatter(formatter)
    
    # Add handler to logger
    logger.addHandler(handler)
    
    return logger

